#include<bits/stdc++.h>
using namespace std;
int n,m,t;
vector<int> v[100010];
int a[100010],flag[100010];
int main()
{
    // freopen("doctor.in","r",stdin);
    // freopen("doctor.out","w",stdout);
    scanf("%d%d%d",&n,&m,&t);
    for(int i=1;i<=m;i++)
    {
        int ts,id;
        scanf("%d%d",&ts,&id);
        v[id].push_back(ts);
    }
    for(int i=1;i<=n;i++)
    {
        sort(v[i].begin(),v[i].end());
        int pre=0;
        for(int j:v[i])
        {
            int len=(j-1)-(pre+1)+1;
            if(len>0)
            {
                a[i]-=len;
                a[i]=max(a[i],0);
                if(flag[i]&&a[i]<=3)
                {
                    flag[i]=0;
                }
            }
            a[i]+=2;
            if(!flag[i]&&a[i]>5)
            {
                flag[i]=1;
            }
            pre=j;
        }
        int len=t-pre;
        if(len>0)
        {
            a[i]-=len;
            a[i]=max(a[i],0);
            if(flag[i]&&a[i]<=3)
            {
                flag[i]=0;
            }
        }
    }
    int ans=0;
    for(int i=1;i<=n;i++)
    {
        ans+=flag[i];
    }
    printf("%d",ans);
    return 0;
}
